module top_module(
    input [63:0] dividend_inverted,
    input [63:0] divisor,
    output reg [63:0] quotient,
    output reg [63:0] remainder
);always @(*) begin
        if (divisor == 0) begin
            quotient = 0;
            remainder = 0;
        end else begin
            quotient = dividend_inverted / divisor;
            remainder = dividend_inverted % divisor;
        end
    end

endmodule
